{
  "name": "Elder Benefit Specialist (EBS) Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; open to all regardless of income.",
    "asset_limits": "No asset limits; open to all regardless of assets.",
    "other_requirements": ["Live in Wisconsin."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, confidential counseling, assistance, and advocacy on public/private benefits (e.g., Social Security, SSI, SSDI, Medicaid, Medicare, SeniorCare, FoodShare, housing/utilities, debt collection, evictions, tenant rights, consumer issues); help with applications, paperwork, appeals, comparing options, and legal rights supervised by elder law attorneys.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Call statewide helpline 1-844-WIS-ADRC (1-844-947-2372)", "Visit FindMyADRC.org to find local Aging and Disability Resource Center (ADRC) or tribal partner", "Contact local county aging office, ADRC, or human/social services department in person or by email/phone (locations vary by county)"],
    "processing_time": "No formal processing; services provided upon contact as available.",
    "waitlist": null,
    "forms": ["No specific application form required; may sign release of information form if needed"],
    "documents": ["No specific documents required initially; bring benefit-related paperwork (e.g., denial letters, income statements, insurance docs) if seeking help with applications/appeals"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Services delivered through local county aging offices, ADRCs, or tribal partners; availability, office hours, and specific staff may vary by county, but core services consistent statewide.",
    "offices_or_providers": ["Local Aging and Disability Resource Centers (ADRCs), county aging offices, tribal partners; find via FindMyADRC.org"]
  },
  "official_source": "https://www.dhs.wisconsin.gov/benefit-specialists/ebs.htm",
  "gotchas": ["Services are assistance/advocacy only, not direct benefits or cash; free but donations encouraged (never required); family/friends/caregivers can participate with permission; not for selling products—unbiased; supervised by attorneys but not full legal representation unless referred."],
  "data_shape_notes": "no income/asset test; statewide via decentralized local ADRC/county offices; advocacy-focused, not entitlement program"
}

{
  "name": "Wisconsin Senior Employment Program (WISE)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are not specified in sources; families must verify current federal poverty guidelines (e.g., via HHS.gov) and confirm ≤125% threshold with local provider[1][2][3][4][6].",
    "asset_limits": "No asset limits mentioned in sources[1][2][3][4][6].",
    "other_requirements": ["Legal resident of Wisconsin[1][3][4]", "Unemployed[1][2][3][4]", "Poor employment prospects (implied by program focus)[6]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time, paid community service training positions (typically 20 hours per week) at host agencies; paid at the highest of federal, state, or local minimum wage; includes skills training, work experience for unsubsidized employment transition, individual job counseling, comprehensive assessment, yearly physical exams, and access to employment opportunities[1][2][3][4].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: (920) 229-5557 (Fox Valley Workforce Development Board)[1]", "Email: info@fvwdb.com[1]", "Email: detwise@dwd.wisconsin.gov (DWD)[3]", "Phone: (608) 242-4928 (Dane County/GWAAR)[5]", "Phone: (608) 243-5670 (GWAAR brochure)[7]", "In-person: Local providers such as Job Center of Wisconsin, Employ Milwaukee, Dane County Job Center (e.g., 1819 Aberg Ave., Madison WI 53704)[3][4][5]"],
    "processing_time": "Not specified in sources",
    "waitlist": "Not mentioned; may vary by local provider capacity",
    "forms": ["No specific form names/numbers listed; contact local provider for application process"],
    "documents": ["Not explicitly listed; prepare proof of age, residency, unemployment status, and income (e.g., tax returns, pay stubs) based on standard requirements"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide to Wisconsin residents; operated through multiple local providers and subgrantees[1][2][3][4][5][6]",
    "regional_variations": "Administered by different organizations by region (e.g., Fox Valley Workforce Development Board in northeast, GWAAR in Dane County, Employ Milwaukee in Milwaukee area); contact info and offices vary; potential differences in availability, wait times, or host agencies by locality[1][4][5]",
    "offices_or_providers": ["Fox Valley Workforce Development Board (920-229-5557)[1]", "GWAAR (608-242-4928 or 608-243-5670, Dane County)[5][7]", "Employ Milwaukee[4]", "Job Center of Wisconsin (detwise@dwd.wisconsin.gov)[3]", "CWI Works subgrantee network including Wisconsin[2]"]
  },
  "official_source": "https://www.dhs.wisconsin.gov/publications/p00409-2024-2027.pdf (Wisconsin SCSEP State Plan 2024-2027); https://www.wisconsinjobcenter.org/ow/ (DWD Job Center)",
  "gotchas": ["Enrollment priority given to veterans/qualified spouses, then those over 65—others may face lower priority[2]", "Temporary/part-time training (not permanent jobs); goal is transition to unsubsidized employment[1][2][6]", "Income limit strictly ≤125% poverty level (family income, not individual)[1][2][6]", "Must be actively unemployed and seeking work; not for current employees[1][4]", "Regional providers differ—contact local office, as no centralized statewide application[1][3][5]", "Paid at minimum wage, not higher despite experience[2][4]"],
  "data_shape_notes": "Statewide but regionally administered via multiple workforce boards and subgrantees; priority tiers affect access; income test at 125% poverty (varies by household size annually); no asset test; part-time hours fixed at ~20/week"
}
